#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
const int N=5010;int dp[N][1<<8],n,p[N],a[N],K,w[N];
//最低未填入的是i，它后面j个的填入情况是S
//dp[i][S] + w_[i] --> dp[i+j][S>>j]
//dp[i][S] + w_[j] --> dp[i][S^(1<<(j-i-1))]

int main()
{
	n=read();K=read();rep(1,n,i)a[p[i]=read()]=i;
	rep(1,n,i)rep(i+1,n,j)if(a[j]<a[i])++w[i];
	memset(dp,0x3f,sizeof(dp));dp[0][0]=0;
	if(n<=K+1){puts("0");return 0;}
	rep(0,n,i)
	{
		int lm=min(K,n-i);
		for(int S=0;S<(1<<lm);++S)
		{
			int j=0;for(;j<=K&&(S>>j&1);++j);++j;
			int wi=w[i];for(int j=0;j<lm;++j)if((S>>j&1)&&a[j+i+1]<a[i])--wi;
			dp[i+j][S>>j]=min(dp[i+j][S>>j],dp[i][S]+wi);
			for(int j=0;j<lm;++j)if(!(S>>j&1))
			{
				int wj=w[i+j+1];for(int k=j+1;k<K;++k)if((S>>k&1)&&a[i+k+1]<a[i+j+1])--wj;
				dp[i][S^(1<<j)]=min(dp[i][S^(1<<j)],dp[i][S]+wj);
			}
		}
	}
	printf("%d\n",dp[n+1][0]);return 0;
}
